import base64
import math
from beeai.events import EventType

def entropy_score(text):
    if not text: return 0
    prob = [float(text.count(c)) / len(text) for c in set(text)]
    return -sum(p * math.log2(p) for p in prob if p > 0)

def detect_hidden_payloads(event):
    if event.type == EventType.TOOL_CALL:
        args = event.data.get('arguments', {})
        for arg_value in args.values():
            if isinstance(arg_value, str):
                # Check for base64 patterns
                if len(arg_value) % 4 == 0 and all(c in 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/=' for c in arg_value):
                    entropy = entropy_score(arg_value)
                    if entropy > 4.5:
                        print(f'🚨 HIGH ENTROPY PAYLOAD: {arg_value[:50]}... (entropy: {entropy:.2f})')
                        return False
    return True

