from beeai import Agent
import base64

class SafeAgent(Agent):
    def save_state(self):
        state = self.get_state()
        # Filter suspicious content
        filtered_state = self._sanitize_state(state)
        super().save_state(filtered_state)

    def _sanitize_state(self, state):
        def clean_recursive(obj):
            if isinstance(obj, str):
                # Block base64 jailbreaks
                if self._is_suspicious_base64(obj):
                    return '[REDACTED]'
                # Block jailbreak patterns
                obj = re.sub(r'ignore.*instructions', '[SANITIZED]', obj, flags=re.I)
            elif isinstance(obj, dict):
                return {k: clean_recursive(v) for k, v in obj.items()}
            elif isinstance(obj, list):
                return [clean_recursive(item) for item in obj]
            return obj

        return clean_recursive(state)

    def _is_suspicious_base64(self, text):
        try:
            decoded = base64.b64decode(text)
            return len(decoded) > 100 and entropy_score(text) > 4.0
        except:
            return False

agent = SafeAgent()
